def ensure_upstream_and_targets(client: KongAdminClient, upstream_cfg: Dict[str, Any]) -> Dict[str, Any]:
    upstream_payload = {k: v for k, v in upstream_cfg.items() if k != "targets"}
    upstream_result = client.upsert_upstream(upstream_payload)

    existing_targets = client.get(f"/upstreams/{upstream_cfg['name']}/targets").get("data", [])
    existing_pairs = {(t.get("target"), t.get("weight")) for t in existing_targets}

    for target in upstream_cfg.get("targets", []):
        pair = (target.get("target"), target.get("weight", 100))
        if pair not in existing_pairs:
            client.create_target(upstream_cfg["name"], target)

    return upstream_result


def configure_kong(client: KongAdminClient, config: Dict[str, Any]) -> Dict[str, Any]:
    results = {"upstreams": [], "services": [], "routes": []}

    for upstream in config.get("upstreams", []):
        result = ensure_upstream_and_targets(client, upstream)
        results["upstreams"].append(result)

    for service in config.get("services", []):
        routes = service.pop("routes", [])
        service_result = client.upsert_service(service)
        results["services"].append(service_result)

        service_name = service["name"]
        for route in routes:
            route_result = client.upsert_route(service_name, route)
            results["routes"].append(route_result)

    return results


